import{c as r,a7 as a,y as i,B as t}from"./chunks/framework.3cjvm90C.js";const g=JSON.parse('{"title":"分布式强化学习","description":"介绍分布式强化学习的主要架构与并行训练方法","frontmatter":{"title":"分布式强化学习","description":"介绍分布式强化学习的主要架构与并行训练方法"},"headers":[],"relativePath":"rlwiki/papers/distributed_rl.md","filePath":"rlwiki/papers/distributed_rl.md","lastUpdated":1782448598000}'),l={name:"rlwiki/papers/distributed_rl.md"};function n(o,e,h,d,s,b){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="分布式强化学习" tabindex="-1">分布式强化学习 <a class="header-anchor" href="#分布式强化学习" aria-label="Permalink to “分布式强化学习”">​</a></h1><h2 id="问题定义和研究动机" tabindex="-1">问题定义和研究动机 <a class="header-anchor" href="#问题定义和研究动机" aria-label="Permalink to “问题定义和研究动机”">​</a></h2><p>分布式强化学习（Distributed RL）是深度强化学习走向大规模应用，解决复杂决策空间和长期规划问题的必经之路。为了解决像星际争霸 2 （SC2） [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id30" target="_blank" rel="noreferrer">1]</a> 和 DOTA2 [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id31" target="_blank" rel="noreferrer">2]</a> 这样超大规模的决策问题，单进程乃至单机器的算力是远远不够的，需要将整个训练管线中的各个部分拓展到各种各样的计算和存储设备上。研究者们希望设计一整套“算法+系统”的方案，能够让 DRL 训练程序便捷地运行在各种不同的计算尺度下，在保证算法优化收敛性的同时，尽可能地提升其中各个环节的效率。</p><p>一般来说，一个强化学习训练程序有三类核心模块，用于和环境交互产生数据的 Collector，其中包含环境本身（Env）和产生动作的 Actor，以及使用这些数据进行训练的 Learner，他们各自需要不同数量和类型的计算资源支持。而根据算法和环境类型的不同，又会有一些延伸的辅助模块，例如大部分 off-policy 算法都会需要数据队列（Replay Buffer）来存储训练数据，对于 model-based RL 相关的算法又会有学习环境 dynamics 的相关训练模块，而对于需要大量自我博弈（self-play）的算法，还需要一个中心化的 Coordinator 去控制协调各个组件（例如动态指定自己博弈的双方）。</p><p>在系统角度，需要让整个训练程序中的同类模块有足够的并行扩展性，例如可以根据需求增加进行交互的环境数量（消耗更多的 CPU），或是增加训练端的吞吐量（通用需要使用更多的 GPU），而对于不同的模块，又希望能够尽可能地让所有的模块可以异步执行，并减小模块时间各种通信方式的代价（网络通信，数据库，文件系统）。但总的来说，一个系统的效率优化的理论上限是——Learner 无等待持续高效训练，即在 Learner 一个训练迭代高效完成时，下一个训练迭代的数据已经准备好。</p><p>在算法角度，则是希望在保证算法收敛性的情况下，降低算法对数据产生吞吐量的要求（例如容忍更旧更 off-policy 的数据），提高数据探索效率和对于已收集数据的利用效率（例如修改数据采样方法，或是结合一些 RL 中 data-efficiency 相关的研究），从而为系统设计提供更大的空间和可能性。</p><p>综上所述，分布式强化学习是一个更加综合的研究子领域，需要深度强化学习算法 + 分布式系统设计的互相感知和协同。</p><h2 id="研究方向" tabindex="-1">研究方向 <a class="header-anchor" href="#研究方向" aria-label="Permalink to “研究方向”">​</a></h2><h3 id="系统" tabindex="-1">系统 <a class="header-anchor" href="#系统" aria-label="Permalink to “系统”">​</a></h3><h4 id="整体架构" tabindex="-1">整体架构 <a class="header-anchor" href="#整体架构" aria-label="Permalink to “整体架构”">​</a></h4><p>对于常见的决策问题，最常用的两种分布式架构就是 IMPALA [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id32" target="_blank" rel="noreferrer">3]</a> 和 SEED RL [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id33" target="_blank" rel="noreferrer">4]</a></p><img src="https://opendilab.github.io/DI-engine/_images/impala.png" alt="../_images/impala.png" style="zoom:20%;"><ul><li>前者是经典的 Actor-Learner 模式，即数据收集和训练端完全分离，定期从 Learner 到 Actor 传递最新的神经网络模型，而 Actor 在收集到一定量的数据后（即 observations）发送给 Learner。如果有多个 Learner，他们还会定期同步神经网络的梯度（即分布式深度学习中的数据并行模式）。</li></ul><img src="https://opendilab.github.io/DI-engine/_images/seed_rl.png" alt="../_images/seed_rl.png" style="zoom:33%;"><ul><li>后者在前者的基础上，致力于去优化传输模型的损耗， SEED RL 将用于推理产生动作的部分剥离出来，也和训练端放在一起，通过高效的 TPU 间通信技术来更新模型，从而大大减少了 IMPALA 中传递模型的代价，而对于环境和推理 Actor 之间的跨机器通信， SEED RL 使用优化过的 gRPC 方案来传递 observation 和 action，从而并不会有太大的负担。</li></ul><blockquote><p>Note</p><p>这两种方案并没有绝对的谁优谁劣，关键在于对于一个实际的决策问题，究竟是跨机器传输模型的代价更大，还是跨机器传输 observation 和 action 等数据的代价更大，如果是前者，且有比较好的 GPU/TPU 间通信组件，那么 SEED RL 是更好的解决方案，如果是后者， IMPALA 是比较稳定的选择。还有， IMPALA 可以累积一批数据后进行数据传递，而 SEED RL 需要每个交互帧都存在数据传输，这属于经典的数据批处理和流处理对比问题，对于目前的机器学习社区前者一般会更简便易用。此外，如果整个训练程序需要更高的自由度和定制化，例如动态控制 Actor 的一些行为， IMPALA 会更为方便一些。</p></blockquote><p>在上述两种架构之外，还有很多其他的分布式强化学习设计方案，例如引入异步神经网络更新方案的 A3C [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id34" target="_blank" rel="noreferrer">5]</a> 和 Gossip A2C [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id35" target="_blank" rel="noreferrer">6]</a>，为了支持大规模自我博弈，设计出复杂 League 机制的 AlphaStar [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id30" target="_blank" rel="noreferrer">1]</a>，结合 model-based RL 和 MCTS 相关模块的 MuZero [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id36" target="_blank" rel="noreferrer">7]</a>.</p><h4 id="单点效率优化" tabindex="-1">单点效率优化 <a class="header-anchor" href="#单点效率优化" aria-label="Permalink to “单点效率优化”">​</a></h4><p>除了整体结构的设计和创新，还有很多对于整个训练程序中某一单点模块进行优化的方法，它们主要是针对某一个子问题，进行专门的定制优化，这里介绍一些主要的方法：</p><ul><li><code>Object Store</code> in Ray/RLLib [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id37" target="_blank" rel="noreferrer">8]</a>: 对于多进程多机器之间的数据传递， Ray/RLLib 中的 Object Store 提供了一种非常便捷高效的方式，任何一个进程，只要知道了这个对象的引用（即 reference），就可以通过向 Store 请求获取相应的值，而具体内部的数据传输完全由 Store 进行管理，这样就可以像写本地单进程程序一样，实现一个分布式训练程序。Object Store 的具体实现是结合 redis， plasma 和 gRPC 完成。</li><li><code>Sample Factory</code> [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id38" target="_blank" rel="noreferrer">9]</a>: Sample Factory 针对单台机器规模的 APPO 算法做了定制化优化，精心设计了一种环境和产生动作的策略之间的异步化方案，并利用 shared memory 大幅提高各模块之间的传输效率。</li><li><code>Reverb</code> in Acme [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id39" target="_blank" rel="noreferrer">10]</a>: Reverb 提供了一套高灵活度和高效率的数据操作和管理模块，对于 RL，很适合用来实现 replay buffer 相关组件。</li><li><code>envpool</code> [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id40" target="_blank" rel="noreferrer">11]</a>: envpool 是目前最快的环境向量化并行方案，利用 c++ threadpool 和许多经典 RL 环境的高效实现，提供了强大的异步向量化环境仿真能力。</li></ul><h3 id="算法" tabindex="-1">算法 <a class="header-anchor" href="#算法" aria-label="Permalink to “算法”">​</a></h3><h4 id="降低算法对数据产生吞吐量的要求" tabindex="-1">降低算法对数据产生吞吐量的要求 <a class="header-anchor" href="#降低算法对数据产生吞吐量的要求" aria-label="Permalink to “降低算法对数据产生吞吐量的要求”">​</a></h4><ul><li><code>V-trace</code> in IMPALA [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id32" target="_blank" rel="noreferrer">3]</a>: off-policy 算法可以拓宽可供训练的数据范围，从而一定程度上提高算法对于旧数据的容忍程度，降低 Collector 端产生数据的吞吐压力，但是过于 off-policy 的数据很容易影响算法的收敛性， IMPALA 中针对这个问题，利用重要性采样机制和相应的裁剪手段，设计了分布式训练设置下一种较稳定的算法方案 V-trace，限制 off-policy 数据对优化本身的负面影响。</li><li><code>Reuse</code> and <code>Staleness</code> in OpenAI FIVE [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id31" target="_blank" rel="noreferrer">2]</a>: 在 OpenAI 针对 DOTA2 设计的智能体中，他们进行了一些关于数据重用次数（Reuse）和折旧程度（Staleness）的实验，过高的重用次数和过旧的数据都会影响大规模训练中 PPO 算法的稳定性。</li></ul><h4 id="提高数据探索效率-对于已收集数据的利用效率" tabindex="-1">提高数据探索效率 + 对于已收集数据的利用效率 <a class="header-anchor" href="#提高数据探索效率-对于已收集数据的利用效率" aria-label="Permalink to “提高数据探索效率 + 对于已收集数据的利用效率”">​</a></h4><ul><li><code>Data Priority and Diversity</code>——Ape-x [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id41" target="_blank" rel="noreferrer">12]</a>: Ape-x 是一种经典的分布式强化学习方案，其中一个核心做法就是利用 Priority Experience Replay，为不同的数据设置不同的采样优先级，让算法更加关注那些“重要”的数据。此外， Ape-x 还在不同的并行 Collector 中设置不同的探索参数（即 eps greedy 的 epsilon）来提升数据多样性。</li><li><code>Representation Learning</code> in RL ——CURL [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id42" target="_blank" rel="noreferrer">13]</a>: 对于一些高维或多模态的输入，可以结合表示学习方法来提升 RL 的数据利用效率，例如对于高维图像输入的控制问题， CURL 引入额外的对比学习过程， RL 在学习到的特征空间上进行决策。而从系统设计来看，表征学习和强化学习训练结合也有很多优化空间，例如两者的异步。</li><li><code>Model-based/MCTS RL</code>——MuZero [<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id36" target="_blank" rel="noreferrer">7]</a>: MuZero 将 model-based RL 和 MCTS RL 结合在一起来提升整体的训练效率，其中包含诸多独有的模块，例如 MCTS 的搜索过程，数据在训练前的 reanalyze 过程等等，相应也会引出更为复杂和多样的分布式强化学习训练系统。</li></ul><h2 id="未来展望" tabindex="-1">未来展望 <a class="header-anchor" href="#未来展望" aria-label="Permalink to “未来展望”">​</a></h2><p>目前，分布式强化学习还只是一个新兴的研究子领域，很多情况下会受限于算力和问题环境，仍然存在很多需要被解决的问题：</p><ul><li>缺少统一的 benchmark 来评价分布式强化学习算法和系统的效率；</li><li>目前大部分分布式强化学习方案都只适用于一小部分环境和一部分 RL 算法，距离技术的通用化还有很远的路要走；</li><li>当前的系统优化和 RL 算法本身仍然是隔离的，可以考虑感知 RL 优化需求的系统设计，例如动态资源感知和调度</li></ul><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to “参考文献”">​</a></h2><p>[1] (<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id3" target="_blank" rel="noreferrer">1</a>,<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id12" target="_blank" rel="noreferrer">2</a>) Oriol Vinyals, Igor Babuschkin, David Silver, et al. Grandmaster level in StarCraft II using multi-agent reinforcement learning. Nat. 575(7782): 350-354 (2019)</p><p>[2] (<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id4" target="_blank" rel="noreferrer">1</a>,<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id23" target="_blank" rel="noreferrer">2</a>)Christopher Berner, Greg Brockman, et al. Dota 2 with Large Scale Deep Reinforcement Learning. CoRR abs/1912.06680 (2019)</p><p>[3] (<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id8" target="_blank" rel="noreferrer">1</a>,<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id22" target="_blank" rel="noreferrer">2</a>)Lasse Espeholt, Hubert Soyer, R émi Munos, et al. IMPALA. Scalable Distributed Deep-RL with Importance Weighted Actor-Learner Architectures. ICML 2018: 1406-1415</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id9" target="_blank" rel="noreferrer">4</a>]Lasse Espeholt, Rapha ël Marinier, Piotr Stanczyk, Ke Wang, Marcin Michalski. SEED RL: Scalable and Efficient Deep-RL with Accelerated Central Inference. ICLR 2020</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id10" target="_blank" rel="noreferrer">5</a>]Volodymyr Mnih, Adri à Puigdom ènech Badia, Mehdi Mirza, Alex Graves, Timothy P. Lillicrap, Tim Harley, David Silver, Koray Kavukcuoglu. Asynchronous Methods for Deep Reinforcement Learning. ICML 2016: 1928-1937</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id11" target="_blank" rel="noreferrer">6</a>]Mahmoud Assran, Joshua Romoff, Nicolas Ballas, Joelle Pineau, Mike Rabbat. Gossip-based Actor-Learner Architectures for Deep Reinforcement Learning. NeurIPS 2019: 13299-13309</p><p>[7] (<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id13" target="_blank" rel="noreferrer">1</a>,<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id27" target="_blank" rel="noreferrer">2</a>)Julian Schrittwieser, Ioannis Antonoglou, Thomas Hubert, Karen Simonyan, Laurent Sifre, Simon Schmitt, Arthur Guez, Edward Lockhart, Demis Hassabis, Thore Graepel, Timothy P. Lillicrap, David Silver. Mastering Atari, Go, Chess and Shogi by Planning with a Learned Model. CoRR abs/1911.08265 (2019)</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id16" target="_blank" rel="noreferrer">8</a>]Eric Liang, Richard Liaw, Robert Nishihara, Philipp Moritz, Roy Fox, Joseph Gonzalez, Ken Goldberg, Ion Stoica. Ray RLLib: A Composable and Scalable Reinforcement Learning Library. CoRR abs/1712.09381 (2017)</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id17" target="_blank" rel="noreferrer">9</a>]Aleksei Petrenko, Zhehui Huang, Tushar Kumar, Gaurav S. Sukhatme, Vladlen Koltun. Sample Factory: Egocentric 3D Control from Pixels at 100000 FPS with Asynchronous Reinforcement Learning. ICML 2020: 7652-7662</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id18" target="_blank" rel="noreferrer">10</a>]Matt Hoffman, Bobak Shahriari, John Aslanides, Gabriel Barth-Maron, Feryal Behbahani, Tamara Norman, Abbas Abdolmaleki, Albin Cassirer, Fan Yang, Kate Baumli, Sarah Henderson, Alexander Novikov, Sergio G ómez Colmenarejo, Serkan Cabi, Çaglar G ül çehre, Tom Le Paine, Andrew Cowie, Ziyu Wang, Bilal Piot, Nando de Freitas. Acme: A Research Framework for Distributed Reinforcement Learning. CoRR abs/2006.00979 (2020)</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id19" target="_blank" rel="noreferrer">11</a>]Jiayi Weng and Min Lin and Zhongwen Xu and Shuicheng Yan. <a href="https://github.com/sail-sg/envpool" target="_blank" rel="noreferrer">https://github.com/sail-sg/envpool</a></p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id25" target="_blank" rel="noreferrer">12</a>]Dan Horgan, John Quan, David Budden, Gabriel Barth-Maron, Matteo Hessel, Hado van Hasselt, David Silver. Distributed Prioritized Experience Replay. ICLR (Poster) 2018</p><p>[<a href="https://opendilab.github.io/DI-engine/02_algo/distributed_rl_zh.html#id26" target="_blank" rel="noreferrer">13</a>]Michael Laskin, Aravind Srinivas, Pieter Abbeel: CURL: Contrastive Unsupervised Representations for Reinforcement Learning. ICML 2020: 5639-5650</p>',42)])])}const _=r(l,[["render",n]]);export{g as __pageData,_ as default};
